CREATE TABLE tb_sys_log (
    log_id varchar(26) NOT NULL,
    log_type_cd varchar(20) NOT NULL,
    proc_user_id varchar(26),
    occur_dtm timestamp DEFAULT current_timestamp NOT NULL,
    log_cont text,
    reg_id varchar(26) DEFAULT 'SYSTEM' NOT NULL,
    reg_dtm timestamp DEFAULT current_timestamp NOT NULL,
    event_type_cd varchar(50) NOT NULL,
    tgt_type_cd varchar(20),
    tgt_id varchar(26),
    proc_result_cd varchar(20) NOT NULL,
    chg_smry_cont text,
    req_trace_id varchar(64),
    access_ip_addr varchar(45),
    CONSTRAINT pk_tb_sys_log PRIMARY KEY (log_id),
    CONSTRAINT ck_tb_sys_log_01 CHECK (proc_result_cd in ('SUCCESS','FAILURE')),
    CONSTRAINT ck_tb_sys_log_02 CHECK ((tgt_type_cd is null and tgt_id is null) or (tgt_type_cd is not null and tgt_id is not null))
);

