CREATE TABLE tb_sales_annc_oppty_rel (
    annc_oppty_rel_id varchar(26) NOT NULL,
    annc_id varchar(26) NOT NULL,
    sales_oppty_id varchar(26) NOT NULL,
    convert_user_id varchar(26) NOT NULL,
    convert_dtm timestamp DEFAULT current_timestamp,
    reg_id varchar(26) NOT NULL,
    reg_dtm timestamp DEFAULT current_timestamp NOT NULL,
    CONSTRAINT pk_tb_sales_annc_oppty_rel PRIMARY KEY (annc_oppty_rel_id)
);

COMMENT ON TABLE tb_sales_annc_oppty_rel IS '사업공고의 영업기회 전환 및 재공고 연결 감사정보';
COMMENT ON COLUMN tb_sales_annc_oppty_rel.annc_oppty_rel_id IS '사업공고영업기회연계의 공고영업기회연계ID';
COMMENT ON COLUMN tb_sales_annc_oppty_rel.annc_id IS '사업공고영업기회연계의 공고ID';
COMMENT ON COLUMN tb_sales_annc_oppty_rel.sales_oppty_id IS '사업공고영업기회연계의 영업기회ID';
COMMENT ON COLUMN tb_sales_annc_oppty_rel.convert_user_id IS '사업공고영업기회연계의 전환자ID';
COMMENT ON COLUMN tb_sales_annc_oppty_rel.convert_dtm IS '사업공고영업기회연계의 전환일시';
COMMENT ON COLUMN tb_sales_annc_oppty_rel.reg_id IS '사업공고영업기회연계의 등록자ID';
COMMENT ON COLUMN tb_sales_annc_oppty_rel.reg_dtm IS '사업공고영업기회연계의 등록일시';

CREATE TABLE tb_sales_oppty (
    sales_oppty_id varchar(26) NOT NULL,
    cust_id varchar(26) NOT NULL,
    oppty_nm varchar(200) NOT NULL,
    sales_stage_cd varchar(20) NOT NULL,
    est_amt numeric(15,2),
    contact_id varchar(26) NOT NULL,
    reg_id varchar(26) NOT NULL,
    reg_dtm timestamp DEFAULT current_timestamp NOT NULL,
    mod_id varchar(26),
    mod_dtm timestamp,
    del_yn char(1) DEFAULT 'N' NOT NULL,
    task_tgt_id varchar(26) NOT NULL,
    CONSTRAINT pk_tb_sales_oppty PRIMARY KEY (sales_oppty_id),
    CONSTRAINT ck_tb_sales_oppty_01 CHECK (est_amt is null or est_amt >= 0),
    CONSTRAINT ck_tb_sales_oppty_02 CHECK (del_yn in ('Y','N'))
);

COMMENT ON TABLE tb_sales_oppty IS '최초 공고부터 재공고와 최종 수주까지 이어지는 영업 단위';
COMMENT ON COLUMN tb_sales_oppty.sales_oppty_id IS '영업기회의 영업기회ID';
COMMENT ON COLUMN tb_sales_oppty.cust_id IS '영업기회의 고객ID';
COMMENT ON COLUMN tb_sales_oppty.oppty_nm IS '영업기회의 명칭';
COMMENT ON COLUMN tb_sales_oppty.sales_stage_cd IS '영업기회의 현재 진행 단계 코드';
COMMENT ON COLUMN tb_sales_oppty.est_amt IS '영업기회의 예상 계약 금액';
COMMENT ON COLUMN tb_sales_oppty.contact_id IS '영업기회를 담당하는 사용자 식별자';
COMMENT ON COLUMN tb_sales_oppty.reg_id IS '영업기회의 등록자ID';
COMMENT ON COLUMN tb_sales_oppty.reg_dtm IS '영업기회의 등록일시';
COMMENT ON COLUMN tb_sales_oppty.mod_id IS '영업기회의 수정자ID';
COMMENT ON COLUMN tb_sales_oppty.mod_dtm IS '영업기회의 수정일시';
COMMENT ON COLUMN tb_sales_oppty.del_yn IS '영업기회의 삭제여부';
COMMENT ON COLUMN tb_sales_oppty.task_tgt_id IS '영업기회의 공통 기능 연결 업무대상 식별자';

CREATE TABLE tb_sales_feas_analysis (
    analysis_id varchar(26) NOT NULL,
    sales_oppty_id varchar(26) NOT NULL,
    est_rev_amt numeric(15,2),
    est_cost_amt numeric(15,2),
    est_profit_amt numeric(15,2),
    est_assign_mm numeric(6,2),
    reg_id varchar(26) NOT NULL,
    reg_dtm timestamp DEFAULT current_timestamp NOT NULL,
    mod_id varchar(26),
    mod_dtm timestamp,
    del_yn char(1) DEFAULT 'N' NOT NULL,
    CONSTRAINT pk_tb_sales_feas_analysis PRIMARY KEY (analysis_id),
    CONSTRAINT ck_tb_sales_feas_analysis_01 CHECK ((est_rev_amt is null or est_rev_amt >= 0) and (est_cost_amt is null or est_cost_amt >= 0) and (est_assign_mm is null or est_assign_mm >= 0)),
    CONSTRAINT ck_tb_sales_feas_analysis_02 CHECK (del_yn in ('Y','N'))
);

COMMENT ON TABLE tb_sales_feas_analysis IS '영업기회별 예상매출 예상원가 예상손익 및 투입 분석';
COMMENT ON COLUMN tb_sales_feas_analysis.analysis_id IS '사업성분석 식별자';
COMMENT ON COLUMN tb_sales_feas_analysis.sales_oppty_id IS '사업성분석의 영업기회ID';
COMMENT ON COLUMN tb_sales_feas_analysis.est_rev_amt IS '사업성분석에서 추정한 매출 금액';
COMMENT ON COLUMN tb_sales_feas_analysis.est_cost_amt IS '사업성분석에서 추정한 원가 금액';
COMMENT ON COLUMN tb_sales_feas_analysis.est_profit_amt IS '예상매출금액에서 예상원가금액을 차감한 예상 손익 금액';
COMMENT ON COLUMN tb_sales_feas_analysis.est_assign_mm IS '사업 수행에 필요할 것으로 예상한 인력 투입량';
COMMENT ON COLUMN tb_sales_feas_analysis.reg_id IS '사업성분석의 등록자ID';
COMMENT ON COLUMN tb_sales_feas_analysis.reg_dtm IS '사업성분석의 등록일시';
COMMENT ON COLUMN tb_sales_feas_analysis.mod_id IS '사업성분석의 수정자ID';
COMMENT ON COLUMN tb_sales_feas_analysis.mod_dtm IS '사업성분석의 수정일시';
COMMENT ON COLUMN tb_sales_feas_analysis.del_yn IS '사업성분석의 삭제여부';

CREATE TABLE tb_sales_prpsl (
    prpsl_id varchar(26) NOT NULL,
    annc_id varchar(26) NOT NULL,
    prpsl_nm varchar(200) NOT NULL,
    submit_dt date,
    prsnt_dt date,
    prpsl_status_cd varchar(20) NOT NULL,
    prpsl_result_cd varchar(20),
    reg_id varchar(26) NOT NULL,
    reg_dtm timestamp DEFAULT current_timestamp NOT NULL,
    mod_id varchar(26),
    mod_dtm timestamp,
    del_yn char(1) DEFAULT 'N' NOT NULL,
    task_tgt_id varchar(26) NOT NULL,
    CONSTRAINT pk_tb_sales_prpsl PRIMARY KEY (prpsl_id),
    CONSTRAINT ck_tb_sales_prpsl_01 CHECK (prsnt_dt is null or submit_dt is null or prsnt_dt >= submit_dt),
    CONSTRAINT ck_tb_sales_prpsl_02 CHECK (del_yn in ('Y','N'))
);

COMMENT ON TABLE tb_sales_prpsl IS '사업공고별 단일 제안 제출정보';
COMMENT ON COLUMN tb_sales_prpsl.prpsl_id IS '제안 식별자';
COMMENT ON COLUMN tb_sales_prpsl.annc_id IS '제안의 공고ID';
COMMENT ON COLUMN tb_sales_prpsl.prpsl_nm IS '제안의 명칭';
COMMENT ON COLUMN tb_sales_prpsl.submit_dt IS '제안서를 제출한 날짜';
COMMENT ON COLUMN tb_sales_prpsl.prsnt_dt IS '제안 발표를 수행한 날짜';
COMMENT ON COLUMN tb_sales_prpsl.prpsl_status_cd IS '제안 업무의 현재 진행 상태 코드';
COMMENT ON COLUMN tb_sales_prpsl.prpsl_result_cd IS '제안 평가 또는 심사의 결과 코드';
COMMENT ON COLUMN tb_sales_prpsl.reg_id IS '제안의 등록자ID';
COMMENT ON COLUMN tb_sales_prpsl.reg_dtm IS '제안의 등록일시';
COMMENT ON COLUMN tb_sales_prpsl.mod_id IS '제안의 수정자ID';
COMMENT ON COLUMN tb_sales_prpsl.mod_dtm IS '제안의 수정일시';
COMMENT ON COLUMN tb_sales_prpsl.del_yn IS '제안의 삭제여부';
COMMENT ON COLUMN tb_sales_prpsl.task_tgt_id IS '제안의 공통 기능 연결 업무대상 식별자';

CREATE TABLE tb_sales_order_rcv (
    ord_rcv_id varchar(26) NOT NULL,
    prpsl_id varchar(26) NOT NULL,
    ord_rcv_yn char(1) NOT NULL,
    ord_rcv_amt numeric(15,2),
    ord_rcv_dt date,
    reg_id varchar(26) NOT NULL,
    reg_dtm timestamp DEFAULT current_timestamp NOT NULL,
    mod_id varchar(26),
    mod_dtm timestamp,
    del_yn char(1) DEFAULT 'N' NOT NULL,
    CONSTRAINT pk_tb_sales_order_rcv PRIMARY KEY (ord_rcv_id),
    CONSTRAINT ck_tb_sales_order_rcv_01 CHECK (ord_rcv_yn in ('Y','N')),
    CONSTRAINT ck_tb_sales_order_rcv_02 CHECK ((ord_rcv_yn = 'Y' and ord_rcv_amt is not null and ord_rcv_amt >= 0 and ord_rcv_dt is not null) or (ord_rcv_yn = 'N' and ord_rcv_amt is null and ord_rcv_dt is null)),
    CONSTRAINT ck_tb_sales_order_rcv_03 CHECK (del_yn in ('Y','N'))
);

COMMENT ON TABLE tb_sales_order_rcv IS '최종 제안의 수주 여부와 결과';
COMMENT ON COLUMN tb_sales_order_rcv.ord_rcv_id IS '수주의 수주ID';
COMMENT ON COLUMN tb_sales_order_rcv.prpsl_id IS '제안 식별자';
