CREATE TABLE tb_res_unit_amt (
    res_unit_amt_id varchar(26) NOT NULL,
    res_id varchar(26) NOT NULL,
    base_ym char(6) NOT NULL,
    mon_unit_amt numeric(15,2),
    day_unit_amt numeric(15,2),
    reg_id varchar(26) NOT NULL,
    reg_dtm timestamp DEFAULT current_timestamp NOT NULL,
    mod_id varchar(26),
    mod_dtm timestamp,
    del_yn char(1) DEFAULT 'N' NOT NULL,
    CONSTRAINT pk_tb_res_unit_amt PRIMARY KEY (res_unit_amt_id),
    CONSTRAINT ck_tb_res_unit_amt_01 CHECK ((mon_unit_amt is not null or day_unit_amt is not null) and (mon_unit_amt is null or mon_unit_amt >= 0) and (day_unit_amt is null or day_unit_amt >= 0)),
    CONSTRAINT ck_tb_res_unit_amt_02 CHECK (base_ym ~ '^[0-9]{4}(0[1-9]|1[0-2])$'),
    CONSTRAINT ck_tb_res_unit_amt_03 CHECK (del_yn in ('Y','N'))
);

