COMMENT ON COLUMN tb_res_unit_amt.mon_unit_amt IS '월 기준 인력 단가';
COMMENT ON COLUMN tb_res_unit_amt.day_unit_amt IS '일 기준 인력 단가';
COMMENT ON COLUMN tb_res_unit_amt.reg_id IS '최초 등록자 식별자';
COMMENT ON COLUMN tb_res_unit_amt.reg_dtm IS '최초 등록 일시';
COMMENT ON COLUMN tb_res_unit_amt.mod_id IS '최종 수정자 식별자';
COMMENT ON COLUMN tb_res_unit_amt.mod_dtm IS '최종 수정 일시';
COMMENT ON COLUMN tb_res_unit_amt.del_yn IS '논리 삭제 여부';

CREATE TABLE tb_res_assign (
    res_assign_id varchar(26) NOT NULL,
