    mod_dtm timestamp,
    del_yn char(1) DEFAULT 'N' NOT NULL,
    CONSTRAINT pk_tb_res_assign PRIMARY KEY (res_assign_id),
    CONSTRAINT ck_tb_res_assign_01 CHECK (assign_end_dt is null or assign_end_dt >= assign_start_dt),
