COMMENT ON COLUMN tb_res_assign.reg_dtm IS '최초 등록 일시';
COMMENT ON COLUMN tb_res_assign.mod_id IS '최종 수정자 식별자';
COMMENT ON COLUMN tb_res_assign.mod_dtm IS '최종 수정 일시';
COMMENT ON COLUMN tb_res_assign.del_yn IS '논리 삭제 여부';

CREATE TABLE tb_res_mthly_assign_actl (
    res_mthly_assign_actl_id varchar(26) NOT NULL,
    res_assign_id varchar(26) NOT NULL,
    base_ym char(6) NOT NULL,
    plan_assign_rate numeric(5,2),
    plan_assign_mm numeric(6,2),
    actl_assign_rate numeric(5,2),
    actl_assign_mm numeric(6,2),
    actl_cnfm_yn char(1) DEFAULT 'N' NOT NULL,
    actl_cnfm_id varchar(26),
    actl_cnfm_dtm timestamp,
    remark_cont text,
    reg_id varchar(26) NOT NULL,
    reg_dtm timestamp DEFAULT current_timestamp NOT NULL,
    mod_id varchar(26),
    mod_dtm timestamp,
    del_yn char(1) DEFAULT 'N' NOT NULL,
    CONSTRAINT pk_tb_res_mthly_assign_actl PRIMARY KEY (res_mthly_assign_actl_id),
    CONSTRAINT ck_tb_res_mthly_assign_actl_01 CHECK (base_ym ~ '^[0-9]{4}(0[1-9]|1[0-2])$'),
    CONSTRAINT ck_tb_res_mthly_assign_actl_02 CHECK ((plan_assign_rate is null or plan_assign_rate between 0 and 100) and (actl_assign_rate is null or actl_assign_rate between 0 and 100)),
    CONSTRAINT ck_tb_res_mthly_assign_actl_03 CHECK ((plan_assign_mm is null or plan_assign_mm >= 0) and (actl_assign_mm is null or actl_assign_mm >= 0)),
    CONSTRAINT ck_tb_res_mthly_assign_actl_04 CHECK (actl_cnfm_yn in ('Y','N')),
    CONSTRAINT ck_tb_res_mthly_assign_actl_05 CHECK ((actl_cnfm_yn = 'Y' and actl_cnfm_id is not null and actl_cnfm_dtm is not null) or (actl_cnfm_yn = 'N' and actl_cnfm_id is null and actl_cnfm_dtm is null)),
    CONSTRAINT ck_tb_res_mthly_assign_actl_06 CHECK (del_yn in ('Y','N'))
);

COMMENT ON TABLE tb_res_mthly_assign_actl IS '인력투입 건의 월별 계획·실적 투입률과 투입MM 정보';
